section.code:
/* Load the messages file. */

if (!msgs_initialise("<ExamplApp$Dir>.Messages"))
	error_report_fatal("Failed to load application Messages");

/* Open the templates file. */

error = xwimp_open_template("<ExamplApp$Dir>.Templates");
if (error != NULL)
	error_report_program(error);

string_copy(resources, "<ExamplApp$Dir>.Resources", MAIN_FILENAME_BUFFER_LEN);
if (!resources_initialise_paths(resources, MAIN_FILENAME_BUFFER_LEN, "ExamplApp$Language", "UK"))
	error_report_fatal("Failed to initialise resources.");

if (!resources_find_file(resources, res_temp, MAIN_FILENAME_BUFFER_LEN, "Messages", osfile_TYPE_TEXT))
	error_report_fatal("Failed to locate suitable Messages file");

if (!msgs_initialise(res_temp)
	error_report_fatal("Failed to load application Messages");

static void main_initialise(void)
{
	char		resources[MAIN_FILENAME_BUFFER_LEN], res_temp[MAIN_FILENAME_BUFFER_LEN];
	os_error	*error;
	osspriteop_area	*sprites;

	/* Initialise the resources. */

	string_copy(resources, "<ExamplApp$Dir>.Resources", MAIN_FILENAME_BUFFER_LEN);
	if (!resources_initialise_paths(resources, MAIN_FILENAME_BUFFER_LEN, "ExamplApp$Language", "UK"))
		error_report_fatal("Failed to initialise resources.");

	/* Load the messages file. */

	if (!resources_find_file(resources, res_temp, MAIN_FILENAME_BUFFER_LEN, "Messages", osfile_TYPE_TEXT))
		error_report_fatal("Failed to locate suitable Messages file");

	if (!msgs_initialise(res_temp)
		error_report_fatal("Failed to load application Messages");

	/* Initialise with the Wimp. */

	wimp_initialise(wimp_VERSION_RO3, main_application_name, NULL, NULL);

	error_initialise(main_application_name, main_application_sprite, NULL);

	event_add_message_handler(message_QUIT, EVENT_MESSAGE_INCOMING, main_message_quit);

	/* Initialise library modules. */

	url_initialise();

	/* Load the application sprites. */

	sprites = resources_load_user_sprite_area("<ExamplApp$Dir>.Sprites");
	if (sprites == NULL)
		error_msgs_report_fatal("BadSprites:Failed to load application Sprites");

	/* Open the templates file. */

	if (!resources_find_file(resources, res_temp, MAIN_FILENAME_BUFFER_LEN, "Templates", osfile_TYPE_TEMPLATE))
		error_report_fatal("MissingTemp:Failed to locate suitable Templates file");

	error = xwimp_open_template(res_temp);
	if (error != NULL)
		error_report_program(error);

	/* Initialise the program modules. */

	calc_initialise();
	ibar_initialise(main_application_sprite);
	win_initialise(sprites);

	/* Close the templates file. */

	wimp_close_template();
}
